import { Session } from "koishi";
import { chatFunctionType, wordDataInputType } from '../driver/src';
export declare const statement: statementType;
export declare const ifStatement: ifStatementType;
export type statementRuleType = (string | number)[];
/**
 * 新增规则
 * @param ruleTrigger 词库语句关键词
 * @param callback 触发时执行的函数，返回值为字符串，此字符串会替换词库语句
 * @returns 当前整个statment规则
 */
export declare const addStatement: (ruleTrigger: string, callback: (inData: chatFunctionType, session: Session | wordDataInputType) => statementCallBackType, rule?: statementRuleType) => statementType;
/**
 * 删除规则
 * @param ruleTrigger 词库语句关键词
 * @returns 当前整个statment规则
 */
export declare const rmStatement: (ruleTrigger: string) => statementType;
export type statementCallBackType = Promise<string | void | statusMsg>;
export type statementType = {
    [key: string]: {
        func: (inData: chatFunctionType, session: Session | wordDataInputType) => statementCallBackType;
        rule?: statementRuleType;
    };
};
export type ifStatementType = {
    [key: string]: {
        func: (inData: chatFunctionType, session: Session | wordDataInputType) => statementCallBackType;
        rule: statementRuleType;
    };
};
export type statusMsg = {
    status: string;
    data?: string;
};
export interface statementFunction {
    statement: statementType;
    ifStatement: ifStatementType;
    addStatement: (ruleTrigger: string, callback: (inData: chatFunctionType, session: Session | wordDataInputType) => statementCallBackType, rule?: statementRuleType) => statementType;
    rmStatement: (ruleTrigger: string) => statementType;
}
